// Normalize incoming payload from either GHL or Notion source
const input = $input.first().json;
const body = input.body || input;

// Extract and normalize
const deal = {
  deal_id: body.deal_id || body.id || `deal_${Date.now()}`,
  source: body.source || 'unknown',
  asset_class: (body.asset_class || body.assetClass || '').trim(),
  market: (body.market || body.deal_market || '').trim(),
  price: parseFloat(body.price || body.deal_price || 0),
  deal_type: body.deal_type || body.dealType || 'Wholesale',
  summary_url: body.summary_url || body.summaryUrl || '',
  address: body.address || '', // internal only, never sent to buyers pre-gate
  blast_at: new Date().toISOString()
};

// Validation gate
if (!deal.asset_class || !deal.market || !deal.price) {
  throw new Error(`Deal missing required fields: asset_class=${deal.asset_class}, market=${deal.market}, price=${deal.price}`);
}

return [{ json: deal }];

// --- auto-generated field ID preamble (2026-04-17T03:40:06.936Z) ---
const FIELD_IDS = {
  "Lead Source": "Ov2LMG8TipkI4jlNAFRR",
  "Buyer Asset Class": "NT3w93SU9mkNugSZjHLB",
  "Buyer Market": "Rt1ETvZZSh3pFlFZkhro",
  "Buyer Price Min": "pM3aeMZALD2tmf2cFSmG",
  "Buyer Price Max": "LcsBYM6iUurqTu8SsfTz",
  "Capital / POF Amount": "pkNBpd4VwNblSMrB20I5",
  "PoF on File": "zKyplmyTeBFlUFdYMfUD",
  "Deals Last 12 Months": "ToK46ItNIDFiEcEFNN5m",
  "Decision Maker": "06k53PRZ8o9hs2Zy5F4h",
  "Buyer Tier": "GzB9iQ9Mb9IsAKuMS93X",
  "Last Touch Date": "SwUKaml8kRpCrrLzunlh",
  "Preferred Contact Method": "qoFIBxIWRow8HQy3GOw1",
  "Re-verify Due Date": "1cgpp0vcBSWSKptqoORU",
  "Entity Name": "05jevWkhMiY8bFoe9TWc",
  "EMD Amount": "pEf6ih4rpT7oOMLlK9wN",
  "Offer Price": "6c52JUALKfX7Apv4RpR4",
  "Close Date Target": "wuXiUAbgKqaYGlmqqE0e",
  "Contingencies": "cTtqBoUEGXEk7gUdtl9u",
  "Assignment Fee Paid": "LkrfGd6ziGJNwlxugcVV",
  "Last Deal Sent ID": "RiSmLK8l97DKzrK3VQaZ",
  "Last Deal Sent Date": "CAJQUQSjrkcdygsCGDdK",
  "Deal Asset Class (latest)": "JzmuiUCvNJtHiHOeEz90",
  "Deal Market (latest)": "tAFA5xs5ZS7AG7AgheZw",
  "Deal Price (latest)": "h1PdpPrgYHfk7WKdEBjp",
  "Deal Type (latest)": "TENFLNR411SHBOBRzEQX",
  "Deal Summary URL (latest)": "hGftrRzv5pt24KrNd1sO"
};
const getFieldById = (buyer, nameKey) => {
  const id = FIELD_IDS[nameKey];
  if (!id) return null;
  const m = (buyer.customFields || []).find(f => f.id === id);
  return m ? m.value : null;
};

// Match logic — filter buyers against deal criteria
const deal = $('Normalize Deal Payload').first().json;
const buyers = $input.first().json.contacts || [];

const matches = [];

for (const buyer of buyers) {
  // Extract custom fields — GHL returns these as an array
  const cf = {};
  (buyer.customFields || []).forEach(f => { cf[f.id] = f.value; });

  // Map by field key (you'll replace these IDs with your actual GHL custom field IDs after first run)
  // Field keys from 01_custom_fields.json — the code below uses the field NAME match as a fallback
  const getField = (name) => {
    const byId = getFieldById(buyer, name);
    if (byId !== null && byId !== undefined) return byId;
    const match = (buyer.customFields || []).find(f => f.name === name || f.fieldKey === name);
    return match ? match.value : null;
  };

  // toArr — GHL multi-select returns arrays; string-type fields return strings. Handle both.
  const toArr = (v) => {
    if (v === null || v === undefined) return [];
    if (Array.isArray(v)) return v.filter(x => x !== null && x !== undefined).map(String).map(s => s.trim()).filter(Boolean);
    if (typeof v === 'string') return v.split(',').map(s => s.trim()).filter(Boolean);
    return [String(v)];
  };

  const buyerAssetClasses = toArr(getField('Buyer Asset Class'));
  const buyerMarkets = toArr(getField('Buyer Market')).map(s => s.toLowerCase());
  const priceMin = parseFloat(getField('Buyer Price Min') || 0);
  const priceMax = parseFloat(getField('Buyer Price Max') || Infinity);
  const buyerTier = (getField('Buyer Tier') || 'C').toUpperCase();
  const lastDealSentDate = getField('Last Deal Sent Date');

  // Cooldown check — skip buyers who got a deal blast in last 24h (spam prevention)
  if (lastDealSentDate) {
    const hoursSince = (Date.now() - new Date(lastDealSentDate).getTime()) / (1000 * 60 * 60);
    if (hoursSince < 24) continue;
  }

  // Asset class match (any overlap)
  const assetMatch = buyerAssetClasses.some(ac => 
    ac.toLowerCase() === deal.asset_class.toLowerCase() ||
    deal.asset_class.toLowerCase().includes(ac.toLowerCase())
  );
  if (!assetMatch) continue;

  // Market match (any substring overlap on buyer market list)
  const dealMarketLower = deal.market.toLowerCase();
  const marketMatch = buyerMarkets.some(bm => 
    dealMarketLower.includes(bm) || bm.includes(dealMarketLower)
  );
  if (!marketMatch) continue;

  // Price band match
  if (deal.price < priceMin || deal.price > priceMax) continue;

  // All checks passed
  matches.push({
    contact_id: buyer.id,
    first_name: buyer.firstName,
    last_name: buyer.lastName,
    email: buyer.email,
    phone: buyer.phone,
    tier: buyerTier,
    tier_priority: buyerTier === 'A' ? 1 : buyerTier === 'B' ? 2 : 3
  });
}

// Sort by tier (A first)
matches.sort((a, b) => a.tier_priority - b.tier_priority);

// Return one item per match so downstream nodes loop naturally
return matches.map(m => ({ json: { ...m, deal } }));

